export const COLLECTIONS = {
  ONE_DAY: {
    slug: "1-hari",
    title: "Paket 1 Hari",
  },

  TWO_DAYS_ONE_NIGHT: {
    slug: "2-hari-1-malam",
    title: "Paket 2 Hari 1 Malam",
  },

  THREE_DAYS_TWO_NIGHTS: {
    slug: "3-hari-2-malam",
    title: "Paket 3 Hari 2 Malam",
  },

  FOUR_DAYS_THREE_NIGHTS: {
    slug: "4-hari-3-malam",
    title: "Paket 4 Hari 3 Malam",
  },

  FIVE_DAYS_FOUR_NIGHTS: {
    slug: "5-hari-4-malam",
    title: "Paket 5 Hari 4 Malam",
  },

  OPEN_TRIP: {
    slug: "open-trip",
    title: "Open Trip",
  },

  SAILING: {
    slug: "sailing",
    title: "Sailing",
  },
} as const;

import type { ImageSource } from "@/lib/images";
import type { COLLECTIONS } from "./collections";

export type PackageCollection = (typeof COLLECTIONS)[keyof typeof COLLECTIONS];

export type Region = "lombok" | "sumbawa" | "labuan-bajo";
export type TourPackage = {
  slug: string;
  title: string;

  region: Region;

  featured?: boolean;

  collectionSlug: string;
  collectionTitle: string;

  category: string;
  duration: string;

  images: ImageSource[];

  summary: string;

  highlights: string[];
  itinerary: string[];

  includes: string[];
  excludes: string[];
};

import { oneDay } from "./1d";

import type { TourPackage } from "../types";
import { threeDays } from "./3d2n";
import { fourDays } from "./4d3n";
import { twoDays } from "./2d1n";
import { motoGP } from "./openTrip";

export const lombokPackages: TourPackage[] = [
  ...oneDay,
  ...twoDays,
  ...threeDays,
  ...fourDays,
  ...motoGP,
];

import type { PackageCollection, TourPackage } from "./types";

export function withCollection(collection: PackageCollection) {
  return {
    collectionSlug: collection.slug,
    collectionTitle: collection.title,
  };
}

export function slugify(text: string): string {
  return text
    .toLowerCase()
    .trim()
    .replace(/[^\w\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-");
}

export function createPackage(
  collection: PackageCollection,
  data: Omit<
    TourPackage,
    "slug" | "collectionSlug" | "collectionTitle" | "featured"
  > & {
    title: string;
    featured?: boolean;
  },
): TourPackage {
  return {
    featured: false,

    ...data,

    slug: slugify(data.title),

    collectionSlug: collection.slug,
    collectionTitle: collection.title,
  };
}

import { lombokPackages } from "./lombok";
import { sumbawaPackages } from "./sumbawa";
import { labuanBajoPackages } from "./labuan-bajo";
import type { TourPackage } from "./types";

export const packages: TourPackage[] = [
  ...lombokPackages,
  ...sumbawaPackages,
  ...labuanBajoPackages,
];

export const getPackageUrl = (pkg: TourPackage) =>
  `/paket-wisata/${pkg.region}/${pkg.collectionSlug}/${pkg.slug}`;

import type { ImageSource } from "@/lib/images";

// ─── Regions ──────────────────────────────────────────────────────────
export type RegionKey = "lombok" | "sumbawa" | "labuan-bajo";
export interface RegionInfo {
  label: string;
  className: string;
}

// ─── Navigation ────────────────────────────────────────────────────────
export type NavCollection = {
  title: string;
  href?: string;
  items: { label: string; href: string }[];
};
export type NavGroup = {
  title: string;
  href?: string;
  collections?: NavCollection[];
  items?: { label: string; href: string }[];
};
export type NavItem = {
  label: string;
  href?: string;
  variant: "link" | "mega" | "dropdown";
  groups?: NavGroup[];
  items?: { label: string; href: string }[];
};

// ─── Tour Packages ─────────────────────────────────────────────────────
export type TourPackage = {
  slug: string;
  title: string;
  region: RegionKey;
  featured?: boolean;
  collectionSlug: string;
  collectionTitle: string;
  category: string;
  duration: string;
  images: ImageSource[];
  summary: string;
  highlights: string[];
  itinerary: string[];
  includes: string[];
  excludes: string[];
};

// ─── Destinations ──────────────────────────────────────────────────────
export type Destination = {
  slug: string;
  title: string;
  region: string;
  image: ImageSource;
  gallery: ImageSource[];
  summary: string;
  thingsToDo: string[];
  packages: string[];
};

// ─── Accommodations ────────────────────────────────────────────────────
export type Accommodation = {
  slug: string;
  name: string;
  region: RegionKey;
  perks: string[];
  regionalHighlights: string[];
  description: string;
  image: ImageSource;
};

// ─── Vehicle / Car Rental ─────────────────────────────────────────────
export type Vehicle = {
  slug: string;
  name: string;
  region: RegionKey;
  pricePerDay: string;
  seats: number;
  transmission: "Manual" | "Automatic";
  features: string[];
  bestFor: string[];
  description: string;
  imageTop: ImageSource;
  imageBottom: ImageSource;
};

// ─── Guides ────────────────────────────────────────────────────────────
export type Guide = {
  slug: string;
  title: string;
  description: string;
  region: RegionKey | "general";
  content: string;
  keyTakeaways: string[];
  bestFor: string[];
  relatedDestinations: string[];
  relatedPackages: string[];
  publishDate: string;
  readingTime: number;
};

// ─── Reviews ───────────────────────────────────────────────────────────
export type Review = {
  author: string;
  source: "Google";
  rating: number;
  date: string;
  text: string;
  initials: string;
};
export type MarqueeReview = {
  quote: string;
  initials: string;
  name: string;
  role: string;
  rating: number;
};

// ─── Landing Page ──────────────────────────────────────────────────────
export interface LandingAction {
  label: string;
  href: string;
  variant: "default" | "outline";
}
export interface LandingHeroCard {
  className: string;
  style: string;
  image?: ImageSource;
  alt?: string;
  title: string;
  description?: string;
  emoji?: string;
  contentSizeClass: string;
  width?: number;
  height?: number;
}
export interface LandingTourCard {
  image: ImageSource;
  duration: string;
  slug: string;
  title: string;
  description: string;
  region: string;
  collectionSlug: string;
}
export interface LandingDestinationCard {
  slug: string;
  title: string;
  description: string;
  image: ImageSource;
}
export interface LandingTransportCard {
  title: string;
  description: string;
}

// ─── Contact ───────────────────────────────────────────────────────────
export interface ContactMethod {
  id: string;
  title: string;
  description: string;
  action?: { label: string; href: string };
}
export interface BusinessInfo {
  name: string;
  description: string;
  phone: string;
  email: string;
  whatsapp: string;
  address: {
    street: string;
    city: string;
    region: string;
    postalCode: string;
    country: string;
  };
  coordinates: { latitude: number; longitude: number };
  socialLinks: {
    instagram?: string;
    facebook?: string;
    tiktok?: string;
    youtube?: string;
  };
}
export interface FormField {
  id: string;
  label: string;
  placeholder: string;
  type: "text" | "email" | "tel" | "number" | "textarea" | "select";
  required?: boolean;
  options?: string[];
}
export type FormContext = "sewa-mobil" | "paket-wisata";

// ─── JSON-LD Schema ────────────────────────────────────────────────────
export type SchemaType =
  | "Organization"
  | "LocalBusiness"
  | "BreadcrumbList"
  | "FAQPage"
  | "TouristAttraction"
  | "Product"
  | "HowTo"
  | "ContactPage";
export interface BreadcrumbItem {
  name: string;
  url: string;
}
export interface FAQItem {
  question: string;
  answer: string;
}

// ─── OG Metadata ───────────────────────────────────────────────────────
export interface OGMetadata {
  title: string;
  description: string;
  image: ImageSource;
  imageAlt: string;
  type?: "website" | "article" | "profile";
}

// ─── Zod Schemas for Runtime Validation ────────────────────────────────
import { z } from "zod";

const regionSchema = z.enum(["lombok", "sumbawa", "labuan-bajo"]);

export const TourPackageSchema = z.object({
  slug: z.string().min(1),
  title: z.string().min(1),
  region: regionSchema,
  featured: z.boolean().optional(),
  collectionSlug: z.string().min(1),
  collectionTitle: z.string().min(1),
  category: z.string().min(1),
  duration: z.string().min(1),
  images: z.array(z.object({ src: z.string() }).or(z.string())).min(1),
  summary: z.string().min(1),
  highlights: z.array(z.string()),
  itinerary: z.array(z.string()).min(1),
  includes: z.array(z.string()),
  excludes: z.array(z.string()),
});

export const DestinationSchema = z.object({
  slug: z.string().min(1),
  title: z.string().min(1),
  region: z.string().min(1),
  image: z.object({ src: z.string() }).or(z.string()),
  gallery: z.array(z.object({ src: z.string() }).or(z.string())),
  summary: z.string().min(1),
  thingsToDo: z.array(z.string()),
  packages: z.array(z.string()),
});

export const AccommodationSchema = z.object({
  slug: z.string().min(1),
  name: z.string().min(1),
  region: regionSchema,
  perks: z.array(z.string()),
  regionalHighlights: z.array(z.string()),
  description: z.string().min(1),
  image: z.object({ src: z.string() }).or(z.string()),
});

export const VehicleSchema = z.object({
  slug: z.string().min(1),
  name: z.string().min(1),
  region: regionSchema,
  pricePerDay: z.string().min(1),
  seats: z.number().int().positive(),
  transmission: z.enum(["Manual", "Automatic"]),
  features: z.array(z.string()),
  bestFor: z.array(z.string()),
  description: z.string().min(1),
  imageTop: z.object({ src: z.string() }).or(z.string()),
  imageBottom: z.object({ src: z.string() }).or(z.string()),
});

---
import OptimizedImage from "@/components/ui/OptimizedImage.astro";

import { BRAND } from "@/assets/images";

import NavigationDesktop from "./NavigationDesktop.astro";
import NavigationMobile from "./NavigationMobile";

import { loadContent } from "@/lib/i18n/loader";

import LocaleSwitcher from "./LocaleSwitcher.astro";
import { localizeHref } from "@/lib/i18n/localize";

interface Props {
  locale?: string;
}

const { locale = "id" } = Astro.props as Props;
const navModule = await loadContent(locale, "navigation");
const { navigation } = navModule;
---

<header
  class="fixed top-0 z-50 w-full text-background border-b border-border/80 bg-black/20 backdrop-blur-md"
>
  <div
    class="mx-auto flex max-w-7xl items-center justify-between gap-4 px-4 py-4 sm:px-6 lg:px-8"
  >
    <a href={localizeHref("/", locale)} class="flex items-center gap-3">
      <OptimizedImage
        src={BRAND.logo}
        alt="Sungkar Group"
        class="h-14 w-auto"
        loading="eager"
      />
    </a>

    <nav class="hidden flex-1 justify-center lg:flex lg:max-w-6xl">
      <NavigationDesktop items={navigation} locale={locale} />
    </nav>

    <div class="hidden items-center gap-3 lg:flex">
      <LocaleSwitcher locale={locale} />
    </div>

    <NavigationMobile items={navigation} locale={locale} client:load />
  </div>
</header>

---
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
} from "@/components/ui/navigation-menu";

import type { NavItem } from "@/lib/content/shared/types";
import { localizeHref } from "@/lib/i18n/localize";
import { t } from "@/lib/i18n/ui-strings";

interface Props {
  items: NavItem[];
  locale?: string;
}

const { items, locale = "id" } = Astro.props as Props;

function lh(href: string | undefined): string | undefined {
  return localizeHref(href, locale);
}
---

<NavigationMenu delayOpen={100}>
  <NavigationMenuList class="items-center gap-1">
    {
      items.map((item) => (
        <NavigationMenuItem value={item.label}>
          {item.variant === "link" && (
            <NavigationMenuLink
              href={lh(item.href!)}
              class="inline-flex h-10 w-max items-center justify-center rounded-md px-3 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground"
            >
              {item.label}
            </NavigationMenuLink>
          )}
          {item.variant === "dropdown" && (
            <>
              <NavigationMenuTrigger class="inline-flex h-10 w-max items-center justify-center rounded-md px-3 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground">
                {item.label}
              </NavigationMenuTrigger>
              <NavigationMenuContent>
                <ul class="w-56 p-1">
                  {item.items?.map((subItem) => (
                    <li>
                      <NavigationMenuLink
                        href={lh(subItem.href)!}
                        class="flex w-full select-none items-center rounded-md px-3 py-2 text-sm leading-none text-muted-foreground hover:bg-accent hover:text-foreground"
                      >
                        {subItem.label}
                      </NavigationMenuLink>
                    </li>
                  ))}
                </ul>
              </NavigationMenuContent>
            </>
          )}
          {item.variant === "mega" && (
            <>
              <NavigationMenuTrigger class="inline-flex h-10 w-max items-center justify-center rounded-md px-3 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground">
                {item.label}
              </NavigationMenuTrigger>
              <NavigationMenuContent>
                <div
                  class="grid gap-3 p-3"
                  style={{
                    gridTemplateColumns: `repeat(${
                      item.groups?.length ?? 1
                    }, minmax(220px, 1fr))`,
                  }}
                >
                  {item.groups?.map((group) => (
                    <div class="rounded-lg border border-border bg-background p-2">
                      <div class="mb-2">
                        {group.href ? (
                          <NavigationMenuLink
                            href={lh(group.href)}
                            class="text-sm font-semibold text-brand-700 hover:underline"
                          >
                            {group.title}
                          </NavigationMenuLink>
                        ) : (
                          <div class="text-sm font-semibold text-brand-700">
                            {group.title}
                          </div>
                        )}
                      </div>
                      {group.collections ? (
                        <ul class="space-y-1">
                          {group.collections.map((collection) => (
                            <li>
                              <NavigationMenuLink
                                href={lh(collection.href!)}
                                class="block rounded-md px-2 py-2 text-sm text-muted-foreground hover:bg-accent hover:text-foreground"
                              >
                                {collection.title}
                              </NavigationMenuLink>
                            </li>
                          ))}
                        </ul>
                      ) : (
                        <ul class="space-y-1">
                          {group.items?.map((subItem) => (
                            <li>
                              <NavigationMenuLink
                                href={lh(subItem.href)}
                                class="block rounded-md px-2 py-2 text-sm text-muted-foreground hover:bg-accent hover:text-foreground"
                              >
                                {subItem.label}
                              </NavigationMenuLink>
                            </li>
                          ))}
                        </ul>
                      )}
                    </div>
                  ))}
                </div>
                {item.href && (
                  <div class="flex justify-center pb-3">
                    <NavigationMenuLink
                      href={lh(item.href)}
                      class="inline-flex items-center rounded-md bg-brand-700 px-4 py-2 text-sm text-background transition-colors hover:bg-brand-500"
                    >
                      {t(locale).common.viewAll} {item.label}
                    </NavigationMenuLink>
                  </div>
                )}
              </NavigationMenuContent>
            </>
          )}
        </NavigationMenuItem>
      ))
    }
  </NavigationMenuList>
</NavigationMenu>

import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerTrigger,
} from "@/components/ui/drawer";

import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

import type { NavItem } from "@/lib/content/shared/types";
import { localizeHref } from "@/lib/i18n/localize";
import {
  LOCALE_LABELS,
  LOCALE_SHORT_LABELS,
  LOCALES,
  getLocalizedPath,
  type Locale,
} from "@/lib/i18n";
import { t } from "@/lib/i18n/ui-strings";

type Props = {
  items: NavItem[];
  locale?: string;
};

const FLAGS: Record<string, string> = {
  id: "\uD83C\uDDEE\uD83C\uDDE9",
  en: "\uD83C\uDDEC\uD83C\uDDE7",
  ar: "\uD83C\uDDF8\uD83C\uDDE6",
  ms: "\uD83C\uDDF2\uD83C\uDDFE",
  zh: "\uD83C\uDDE8\uD83C\uDDF3",
};

export default function NavigationMobile({ items, locale = "id" }: Props) {
  const lh = (href: string | undefined) => localizeHref(href, locale);

  return (
    <div className="lg:hidden">
      <Drawer>
        <DrawerTrigger asChild>
          <button
            className="
              rounded-full
              border
              border-white/20
              bg-white/10
              px-4
              py-2
              text-sm
              font-medium
              text-white
              backdrop-blur-md
            "
          >
            {t(locale).header.menu}
          </button>
        </DrawerTrigger>

        <DrawerContent className="h-[85vh]">
          <DrawerHeader className="space-y-2 pb-2">
            <DrawerTitle className="text-center text-xl font-medium font-sans">
              {t(locale).header.exploreDestinations}
            </DrawerTitle>

            <p className="text-center text-sm text-muted-foreground">
              Lombok • Sumbawa • Labuan Bajo
            </p>
          </DrawerHeader>

          <div className="flex flex-1 flex-col font-sans overflow-hidden">
            <div className="flex-1 overflow-y-auto px-6 min-h-0">
              <div className="mb-4 border-b border-border pb-4">
                <p className="mb-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                  {t(locale).header.language}
                </p>
                <div className="flex flex-wrap gap-1.5">
                  {LOCALES.map((l) => {
                    const isCurrent = l === locale;
                    return (
                      <a
                        key={l}
                        href={
                          isCurrent
                            ? undefined
                            : getLocalizedPath(
                                typeof window !== "undefined"
                                  ? window.location.pathname
                                  : "/",
                                l,
                              )
                        }
                        className={`inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium transition-colors ${
                          isCurrent
                            ? "bg-primary text-primary-foreground"
                            : "bg-muted text-muted-foreground hover:bg-accent hover:text-foreground"
                        }`}
                      >
                        <span className="text-base leading-none">
                          {FLAGS[l]}
                        </span>
                        <span>{LOCALE_SHORT_LABELS[l as Locale]}</span>
                        <span className="hidden sm:inline">
                          {LOCALE_LABELS[l as Locale]}
                        </span>
                      </a>
                    );
                  })}
                </div>
              </div>
              <nav className="flex flex-col [&_h3]:font-sans">
                {items.map((item) => {
                  if (item.variant === "link") {
                    return (
                      <a
                        key={item.label}
                        href={lh(item.href)}
                        className="
                          py-4
                          text-base
                          text-foreground
                        "
                      >
                        {item.label}
                      </a>
                    );
                  }

                  if (item.variant === "dropdown") {
                    return (
                      <Accordion
                        key={item.label}
                        className="border-none bg-background"
                      >
                        <AccordionItem
                          value={item.label}
                          className="border-none bg-background"
                        >
                          <AccordionTrigger
                            className="
                              bg-background
                              py-4
                              text-base
                              pl-0
                              font-normal
                              hover:no-underline
                            "
                          >
                            {item.label}
                          </AccordionTrigger>

                          <AccordionContent>
                            <div className="grid gap-1 pl-4 pb-2">
                              {item.items?.map((subItem) => (
                                <a
                                  key={subItem.href}
                                  href={lh(subItem.href)}
                                  className="
                                    py-2
                                    text-sm
                                    text-muted-foreground
                                    transition-colors
                                    hover:text-foreground
                                  "
                                >
                                  {subItem.label}
                                </a>
                              ))}
                            </div>
                          </AccordionContent>
                        </AccordionItem>
                      </Accordion>
                    );
                  }

                  return (
                    <Accordion
                      key={item.label}
                      className="border-none bg-background"
                    >
                      <AccordionItem
                        value={item.label}
                        className="border-none bg-background"
                      >
                        <AccordionTrigger
                          className="
                            bg-background
                            py-4
                            text-base
                            pl-0
                            font-normal
                            hover:no-underline
                          "
                        >
                          {item.label}
                        </AccordionTrigger>

                        <AccordionContent>
                          <Accordion className="pb-2 border-none bg-background">
                            {item.groups?.map((group) => {
                              const shortTitle = group.title
                                .replace("Paket Wisata ", "")
                                .replace("Open Trip ", "");

                              return (
                                <AccordionItem
                                  key={group.title}
                                  value={group.title}
                                  className="border-none"
                                >
                                  <AccordionTrigger
                                    className="
                                      py-3
                                      text-sm
                                      font-normal
                                      text-muted-foreground
                                      bg-background
                                    "
                                  >
                                    <div className="flex items-center w-full justify-between gap-2">
                                      <span>{shortTitle}</span>

                                      <span className="inline-flex items-center justify-center rounded-full border border-transparent bg-primary text-primary-foreground text-xs font-medium px-4 py-1 ">
                                        {group.collections?.length
                                          ? group.collections.reduce(
                                              (acc, collection) =>
                                                acc + collection.items.length,
                                              0,
                                            )
                                          : (group.items?.length ?? 0)}
                                      </span>
                                    </div>
                                  </AccordionTrigger>

                                  <AccordionContent className="bg-background">
                                    {group.collections?.length ? (
                                      <div className="space-y-4 pl-4">
                                        {group.collections.map((collection) => (
                                          <div key={collection.title}>
                                            <a
                                              href={lh(collection.href)}
                                              className="
                                                mb-2
                                                block
                                                text-xs
                                                font-medium
                                                uppercase
                                                tracking-wide
                                                text-brand-700
                                              "
                                            >
                                              {collection.title}
                                            </a>

                                            <div className="grid gap-1">
                                              {collection.items.map(
                                                (subItem) => (
                                                  <a
                                                    key={subItem.href}
                                                    href={lh(subItem.href)}
                                                    className="
                                                    py-2
                                                    text-sm
                                                    text-muted-foreground
                                                    transition-colors
                                                    hover:text-foreground
                                                  "
                                                  >
                                                    {subItem.label}
                                                  </a>
                                                ),
                                              )}
                                            </div>
                                          </div>
                                        ))}
                                      </div>
                                    ) : (
                                      <div className="grid gap-1 pl-4">
                                        {group.items?.map((subItem) => (
                                          <a
                                            key={subItem.href}
                                            href={lh(subItem.href)}
                                            className="
                                              py-2
                                              text-sm
                                              text-muted-foreground
                                              transition-colors
                                              hover:text-foreground
                                            "
                                          >
                                            {subItem.label}
                                          </a>
                                        ))}
                                      </div>
                                    )}
                                  </AccordionContent>
                                </AccordionItem>
                              );
                            })}
                          </Accordion>
                        </AccordionContent>
                      </AccordionItem>
                    </Accordion>
                  );
                })}
              </nav>
            </div>
          </div>
        </DrawerContent>
      </Drawer>
    </div>
  );
}

