export function getStaticPaths() {
  const paths = [];
  const uniqueColl = packages
    .map((pkg) => ({
      region: pkg.region,
      collection: pkg.collectionSlug,
    }))
    .filter(
      (value, index, self) =>
        index ===
        self.findIndex(
          (item) =>
            item.region === value.region &&
            item.collection === value.collection,
        ),
    );
  for (const item of uniqueColl) {
    paths.push({ params: { ...item } });
  }
  return paths;
}

