  regionPackages.reduce<Record<string, CCard>>((acc, pkg) => {
    if (!acc[pkg.collectionSlug]) {
      acc[pkg.collectionSlug] = {
        slug: pkg.collectionSlug,
        title: pkg.collectionTitle,
        packages: [],
