import MainLayout from "@/layouts/MainLayout.astro";
import OptimizedImage from "@/components/ui/OptimizedImage.astro";
import StructuredData from "@/components/seo/StructuredData.astro";
import { generateProductSchema, generateBreadcrumbSchema, generateFAQPageSchema } from "@/lib/schemas";
import { SITE_URL } from "@/lib/site-config";

import { packages } from "@/lib/content/tourPackages/index";
import { REGION_LABEL, type RegionKey as Region } from "@/lib/regions";

import PageHeader from "@/components/site/PageHeader.astro";
import PackageItinerary from "@/components/packages/PackageItinerary.astro";
import PackageIncludesExcludes from "@/components/packages/PackageIncludesExcludes.astro";
import PackageGallery from "@/components/packages/PackageGallery";
import FaqSection from "@/components/site/Faq.astro";
import SectionContainer from "@/layouts/SectionContainer.astro";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";
import WhatsAppForm from "@/components/contact/WhatsAppForm.astro";
import { paketWisataFormFields } from "@/lib/contact-data";

import { loadFaq } from "@/lib/i18n/loader";
import { t } from "@/lib/i18n";
import { getImageSrc } from "@/lib/images";


export function getStaticPaths() {
  const paths = [];
  for (const tour of packages) {
    paths.push({
      params: {
        region: tour.region,
        collection: tour.collectionSlug,
        slug: tour.slug,
      },
      props: { tour },
    });
  }
  return paths;
}

const locale = "id";
const { tour } = Astro.props;
const uiStrings = t(locale);

const r = tour.region as Region;

const packageUrl = `${SITE_URL}/paket-wisata/${tour.region}/${tour.collectionSlug}/${tour.slug}`;
const absoluteImageUrl = new URL(getImageSrc(tour.images[0]), SITE_URL).toString();

const productSchema = generateProductSchema(
  tour.title,
  tour.summary,
  uiStrings.common.contactForPrice,
  absoluteImageUrl,
  packageUrl,
  tour.duration,
);

const faqModule = await loadFaq(locale, "package");
const { packageFaq } = faqModule;

const faqSchema = generateFAQPageSchema(packageFaq);

const breadcrumbItems = [
  { name: uiStrings.breadcrumb.home, url: "/" },
  { name: uiStrings.breadcrumb.tourPackages, url: "/paket-wisata" },
  { name: REGION_LABEL[r], url: `/paket-wisata/${tour.region}` },
  { name: tour.collectionTitle, url: `/paket-wisata/${tour.region}/${tour.collectionSlug}` },
  { name: tour.title, url: `/paket-wisata/${tour.region}/${tour.collectionSlug}/${tour.slug}` },
];

const breadcrumbSchema = generateBreadcrumbSchema(breadcrumbItems, SITE_URL);

const itineraryByDay = Object.entries(
  tour.itinerary.reduce((acc: Record<string, string[]>, item: string) => {
    const [day, ...rest] = item.split(" - ");
    const description = rest.join(" - ");
    if (!acc[day]) {
      acc[day] = [];
    }
    acc[day].push(description);
    return acc;
  }, {}),
);
---

<MainLayout
  title={tour.title}
  description={tour.summary}
  canonical={`/paket-wisata/${tour.region}/${tour.collectionSlug}/${tour.slug}`}
  image={tour.images[0]}
  locale={locale}
>
  <StructuredData schema={productSchema} />
  <StructuredData schema={breadcrumbSchema} />
  <StructuredData schema={faqSchema} />

  <PageHeader
    title={tour.title}
    description={tour.summary}
