      { label: tour.title },
    ]}
    image={tour.images[0]}
    imageAlt={tour.title}
    stats={[
      { label: uiStrings.paketWisata.duration, value: tour.duration },
      { label: uiStrings.paketWisata.category, value: tour.category },
